  1→import React, { useState, useEffect } from 'react';
  2→import { AnalysisResult, User, SMCContent } from '../types';
  3→import { generateJsonLd, generateSchemaWithAI, SchemaInput } from '../services/schema_service';
  4→import PageHeader from '../components/layout/PageHeader';
  5→import { ArrowLeft, Code, Download, Copy, Check, ShieldCheck, Globe, Share2, Building2, Phone, Mail, Image as ImageIcon, ExternalLink, RefreshCw, Zap, Archive, Eye, Sparkles, Loader2 } from 'lucide-react';
  6→
  7→interface Props {
  8→  onBack: () => void;
  9→  history: AnalysisResult[];
 10→  user: User | null;
 11→  onDeductCredits: (amount: number) => boolean;
 12→  savedFiles: SMCContent[];
 13→  onSaveFile: (item: SMCContent) => void;
 14→}
 15→
 16→const SchemaOrg: React.FC<Props> = ({ onBack, history, user, onDeductCredits, savedFiles, onSaveFile }) => {
 17→  const [copied, setCopied] = useState(false);
 18→  const [formData, setFormData] = useState<SchemaInput>({
 19→    name: '',
 20→    url: '',
 21→    logoUrl: '',
 22→    description: '',
 23→    socialProfiles: ['', '', ''],
 24→    contactPhone: '',
 25→    contactEmail: '',
 26→    alternateName: ''
 27→  });
 28→  
 29→  const [jsonOutput, setJsonOutput] = useState('');
 30→  const [isGenerated, setIsGenerated] = useState(false);
 31→  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
 32→  const [generationMode, setGenerationMode] = useState<'local' | 'ai'>('local');
 33→
 34→  // Pré-remplissage basé sur l'historique
 35→  useEffect(() => {
 36→    if (history.length > 0) {
 37→      const latest = history[0];
 38→      const urlObj = new URL(latest.url);
 39→      const hostname = urlObj.hostname;
 40→      const name = hostname.replace('www.', '').split('.')[0];
 41→      const formattedName = name.charAt(0).toUpperCase() + name.slice(1);
 42→
 43→      setFormData(prev => ({
 44→        ...prev,
 45→        name: formattedName,
 46→        url: urlObj.origin,
 47→        logoUrl: `${urlObj.origin}/logo.png`,
 48→        description: `Site officiel de ${formattedName}.`,
 49→        contactEmail: `contact@${hostname}`
 50→      }));
 51→    }
 52→  }, [history]);
 53→
 54→  // Régénération automatique à chaque changement du formulaire
 55→  useEffect(() => {
 56→    if (isGenerated) {
 57→        setJsonOutput(generateJsonLd(formData));
 58→    }
 59→  }, [formData, isGenerated]);
 60→
 61→  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
 62→    setFormData({ ...formData, [e.target.name]: e.target.value });
 63→  };
 64→
 65→  const handleSocialChange = (index: number, value: string) => {
 66→    const newSocials = [...formData.socialProfiles];
 67→    newSocials[index] = value;
 68→    setFormData({ ...formData, socialProfiles: newSocials });
 69→  };
 70→
 71→  const handleGenerate = async (mode: 'local' | 'ai' = 'local') => {
 72→    const cost = mode === 'ai' ? 8 : 5;
 73→    if (!onDeductCredits(cost)) return;
 74→
 75→    setGenerationMode(mode);
 76→
 77→    if (mode === 'ai') {
 78→      // Check pre-generated cache first (only if form hasn't been significantly modified from defaults)
 79→      const cachedSchema = history.length > 0 ? history[0]?.preGenerated?.schemaOrg : undefined;
 80→      if (cachedSchema?.content) {
 81→        setJsonOutput(cachedSchema.content);
 82→        setIsGenerated(true);
 83→        onSaveFile({
 84→          id: `schema_ai_${Date.now()}`,
 85→          type: 'fiche',
 86→          title: `Schema Organization (AI) - ${formData.name}`,
 87→          content: cachedSchema.content,
 88→          timestamp: new Date().toISOString()
 89→        });
 90→        return;
 91→      }
 92→
 93→      setIsGeneratingAI(true);
 94→      try {
 95→        const result = await generateSchemaWithAI(formData);
 96→        setJsonOutput(result.content);
 97→        setIsGenerated(true);
 98→        onSaveFile({
 99→          id: `schema_ai_${Date.now()}`,
100→          type: 'fiche',
