 17→const RobotsTxt: React.FC<Props> = ({ onBack, history, user, onDeductCredits, onUpdateAnalysis, savedFiles, onSaveFile }) => {
 18→  const [selectedAnalysisIndex, setSelectedAnalysisIndex] = useState<number>(0);
 19→  const [currentContent, setCurrentContent] = useState('');
 20→  const [optimizedContent, setOptimizedContent] = useState('');
 21→  const [platformName, setPlatformName] = useState('');
 22→  const [copied, setCopied] = useState(false);
 23→  const [isUnlocked, setIsUnlocked] = useState(false);
 24→  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
 25→
 26→  const GENERATION_COST = 10;
 27→  const AI_GENERATION_COST = 15;
 28→
 29→  // Initialize with data from history
 30→  useEffect(() => {
 31→    const processUrl = (analysis: AnalysisResult | undefined) => {
 32→        if (!analysis) {
 33→            // Mode Demo / Fallback
 34→            const demoUrl = "https://monsite-wordpress.com";
 35→            setCurrentContent(parseCurrentRobotsTxt(demoUrl));
 36→            setOptimizedContent(generateOptimizedRobotsTxt(demoUrl));
 37→            setPlatformName(getDetectedPlatformName(demoUrl));
 38→            setIsUnlocked(false);
 39→            return;
 40→        }
 41→
 42→        const url = analysis.url;
 43→        setCurrentContent(parseCurrentRobotsTxt(url));
 44→        setPlatformName(getDetectedPlatformName(url));
 45→
 46→        // Check if previously unlocked/saved in history
 47→        if (analysis.robotsTxtData && analysis.robotsTxtData.isUnlocked) {
 48→            setOptimizedContent(analysis.robotsTxtData.content);
 49→            setIsUnlocked(true);
 50→        } else {
 51→            // Fresh generation (locked)
 52→            setOptimizedContent(generateOptimizedRobotsTxt(url));
 53→            setIsUnlocked(false);
 54→        }
 55→    };
 56→
 57→    if (history.length > 0) {
 58→      processUrl(history[selectedAnalysisIndex]);
 59→    } else {
 60→      processUrl(undefined);
 61→    }
 62→  }, [selectedAnalysisIndex, history]);
 63→
 64→  const handleUnlock = () => {
 65→    if (onDeductCredits(GENERATION_COST)) {
 66→        setIsUnlocked(true);
 67→
 68→        if (history.length > 0) {
 69→            onUpdateAnalysis(selectedAnalysisIndex, {
 70→                robotsTxtData: {
 71→                    content: optimizedContent,
 72→                    isUnlocked: true,
 73→                    platform: platformName,
 74→                    generatedAt: new Date().toISOString()
 75→                }
 76→            });
 77→        }
