 99→      setPlatformName(cachedRobots.platformDetected);
100→      setIsUnlocked(true);
101→
102→      if (history.length > 0) {
103→        onUpdateAnalysis(selectedAnalysisIndex, {
104→          robotsTxtData: {
105→            content: cachedRobots.content,
106→            isUnlocked: true,
107→            platform: cachedRobots.platformDetected,
108→            generatedAt: new Date().toISOString()
109→          }
110→        });
111→      }
112→
113→      onSaveFile({
114→        id: `robots_ai_${Date.now()}`,
115→        type: 'fiche',
116→        title: `Robots.txt (AI) - ${history[selectedAnalysisIndex]?.url || 'Demo'}`,
117→        content: cachedRobots.content,
118→        timestamp: new Date().toISOString()
119→      });
120→      return;
