133→          robotsTxtData: {
134→            content: result.content,
135→            isUnlocked: true,
136→            platform: result.platformDetected,
137→            generatedAt: new Date().toISOString()
138→          }
139→        });
140→      }
141→
142→      onSaveFile({
143→        id: `robots_ai_${Date.now()}`,
144→        type: 'fiche',
145→        title: `Robots.txt (AI) - ${history[selectedAnalysisIndex]?.url || 'Demo'}`,
146→        content: result.content,
147→        timestamp: new Date().toISOString()
148→      });
149→    } catch {
150→      // Fallback to local generation
151→      setIsUnlocked(true);
152→    } finally {
153→      setIsGeneratingAI(false);
154→    }
